/**
 * Pre-process: detect payload shape, detect language, attach metadata.
 * Field mapping is delegated to per-shape Set nodes downstream.
 */
const body = $input.first().json.body || $input.first().json;

function detectShape(p) {
  if (p.form_data) return "website_form";
  if (p.lead && p.partner) return "partner_referral";
  if (p.attendee) return "event";
  return "generic";
}

function getMessage(p) {
  return p.form_data?.message
    || p.lead?.message
    || p.attendee?.notes
    || p.message
    || p.raw_message
    || "";
}

function getDeclaredLang(p) {
  return p.form_data?.language
    || p.lead?.language
    || p.attendee?.lang
    || p.language
    || null;
}

function detectLanguage(text, declared) {
  if (declared && ["en", "ar"].includes(String(declared).toLowerCase())) {
    return String(declared).toLowerCase();
  }
  // Arabic Unicode block detection
  return /[\u0600-\u06FF]/.test(text || "") ? "ar" : "en";
}

return [{
  json: {
    _shape: detectShape(body),
    _language: detectLanguage(getMessage(body), getDeclaredLang(body)),
    _request_id: "req_" + Date.now().toString(36) + "_" + Math.random().toString(36).slice(2, 10),
    _ingested_at: new Date().toISOString(),
    _schema_version: "1.0.0",
    body
  }
}];

/**
 * Final cleanup + validation.
 * - Normalizes email (lowercase, trim), country (UPPER, 2-letter), phone (digits + leading +)
 * - Drops the raw `body` (keeps audit trail via _request_id elsewhere)
 * - Adds derived fields (email_domain)
 * - Validates required fields, attaches _validation block
 *
 * Soft-fail philosophy: invalid leads still pass through but are flagged.
 * Routing layer decides what to do with invalid leads (typically: write to a
 * "rejects" log + Slack alert, do not push to CRM).
 */

const item = $input.item.json;

function normEmail(e) {
  return (e || "").toString().trim().toLowerCase() || null;
}

function normCountry(c) {
  if (!c) return null;
  return c.toString().trim().toUpperCase().slice(0, 2);
}

function normPhone(p) {
  if (!p) return null;
  return p.toString().replace(/[^\d+]/g, "") || null;
}

function nullIfEmpty(v) {
  if (v === undefined || v === null) return null;
  if (typeof v === "string" && v.trim() === "") return null;
  return v;
}

function emailDomain(email) {
  if (!email) return null;
  const at = email.indexOf("@");
  return at > -1 ? email.slice(at + 1) : null;
}

const email = normEmail(item.email);

const lead = {
  // canonical fields
  company_name: nullIfEmpty((item.company_name || "").toString().trim()),
  contact_name: nullIfEmpty((item.contact_name || "").toString().trim()),
  email,
  email_domain: emailDomain(email),
  phone: normPhone(item.phone),
  country: normCountry(item.country),
  company_size: nullIfEmpty(item.company_size),
  source: item.source || "unknown",
  raw_message: nullIfEmpty((item.raw_message || "").toString().trim()),
  language: item._language || "en",

  // extended fields (used by scoring + enrichment downstream)
  form_intent: nullIfEmpty(item.form_intent),
  visit_count: Number(item.visit_count) || 0,
  industry: nullIfEmpty(item.industry),
  website: null,
  tech_stack: [],

  // shape-specific extras (only present on some sources)
  company_name_native: nullIfEmpty(item.company_name_native),
  partner_name: nullIfEmpty(item.partner_name),
  partner_id: nullIfEmpty(item.partner_id),
  event_name: nullIfEmpty(item.event_name),

  // timestamps
  submitted_at: item.submitted_at || new Date().toISOString(),

  // ingestion metadata
  _request_id: item._request_id,
  _source_shape: item._shape,
  _ingested_at: item._ingested_at,
  _schema_version: item._schema_version
};

// --- Validation ---
const errors = [];
const warnings = [];

if (!lead.email) errors.push("email missing");
if (!lead.company_name) errors.push("company_name missing");
if (!lead.country) errors.push("country missing");

if (!lead.company_size) warnings.push("company_size missing — confidence will drop");
if (!lead.raw_message) warnings.push("raw_message missing — intent score will be low");
if (!lead.industry) warnings.push("industry missing — enrichment will need to fill this");

lead._validation = {
  valid: errors.length === 0,
  errors,
  warnings
};

return { json: lead };

/**
 * Dedup check — merges HubSpot search result back with the canonical lead.
 *
 * Outcomes:
 *  - existing_customer = true  → contact found in HubSpot, route to AM downstream
 *  - existing_customer = false → new lead, continue normal flow
 *
 * Match strategy here is exact email. The next iteration could add
 * email-domain + company-name fuzzy match for the case where someone
 * submits with a different email but same company.
 */

const lead = $('Validate & Finalize').item.json;
const search = $input.item.json;

const found = (search.results || [])[0] || null;

const enriched = {
  ...lead,
  existing_customer: !!found,
  hubspot_contact_id: found?.id || null,
  hubspot_existing_properties: found?.properties || null,
  _dedup: {
    matched_on: found ? "email_exact" : null,
    search_total: search.total || 0
  }
};

return { json: enriched };

/**
 * Mock enrichment — simulates an Exa/Clearbit lookup keyed on email domain.
 *
 * In production this is a swap-in HTTP call — the interface is identical:
 * input domain → output { industry, website, tech_stack, employees_estimate }.
 *
 * Additive: never overwrites fields the inbound lead already provided.
 * Confidence drops only for fields that even enrichment couldn't fill.
 */

const lead = $input.item.json;
const domain = lead.email_domain;

// Mock dataset keyed by email domain. In production: replace with Exa.
const MOCK_DB = {
  "falconlogistics.ae":   { industry: "logistics",            website: "https://falconlogistics.ae",   tech_stack: ["xero", "google sheets"],  employees_estimate: 200 },
  "alnajm-trading.sa":    { industry: "retail",               website: "https://alnajm-trading.sa",    tech_stack: ["excel"],                  employees_estimate: 15  },
  "brightspark.ae":       { industry: "media",                website: "https://brightspark.ae",       tech_stack: ["zoho books"],             employees_estimate: 45  },
  "cairotech.eg":         { industry: "saas",                 website: "https://cairotech.eg",         tech_stack: ["spendesk", "quickbooks"], employees_estimate: 80  },
  "desertrose.ae":        { industry: "hospitality",          website: "https://desertrose.ae",        tech_stack: ["tally"],                  employees_estimate: 60  },
  "emiratesconstruction.ae": { industry: "construction",      website: "https://emiratesconstruction.ae", tech_stack: ["sage", "manual"],     employees_estimate: 350 },
  "greenleaf.ca":         { industry: "agriculture",          website: "https://greenleaf.ca",         tech_stack: [],                         employees_estimate: 8   },
  "aub.edu.lb":           { industry: "education",            website: "https://aub.edu.lb",           tech_stack: [],                         employees_estimate: 5000 },
  "oldco.ae":             { industry: "professional services",website: "https://oldco.ae",             tech_stack: ["excel"],                  employees_estimate: 30  },
  "acme.ae":              { industry: "saas",                 website: "https://acme.ae",              tech_stack: ["xero"],                   employees_estimate: 100 }
};

function lookup(domain) {
  if (!domain) return null;
  // Exact match first
  if (MOCK_DB[domain]) return MOCK_DB[domain];
  // Public-domain emails (gmail, etc.) → can't enrich from domain alone
  const PUBLIC_DOMAINS = ["gmail.com", "yahoo.com", "hotmail.com", "outlook.com", "icloud.com"];
  if (PUBLIC_DOMAINS.includes(domain.toLowerCase())) return { _public_email: true };
  return null;
}

const enrichment = lookup(domain);
const found = enrichment && !enrichment._public_email;

// Additive merge: only fill what's missing in the original lead
const enriched = {
  ...lead,
  industry:           lead.industry           || (found ? enrichment.industry           : null),
  website:            lead.website            || (found ? enrichment.website            : null),
  tech_stack:         (lead.tech_stack && lead.tech_stack.length) ? lead.tech_stack
                                              : (found ? enrichment.tech_stack          : []),
  // Keep original company_size if provided; only fall back to enrichment
  company_size:       lead.company_size       || (found ? enrichment.employees_estimate : lead.company_size),
  _enrichment: {
    mode: "mock",
    matched: found,
    matched_on: found ? "email_domain_exact" : null,
    domain,
    is_public_email: !!(enrichment && enrichment._public_email),
    fields_filled: found
      ? ["industry","website","tech_stack","company_size"].filter(f => !lead[f] || (Array.isArray(lead[f]) && !lead[f].length))
      : []
  }
};

return { json: enriched };

