/**
 * Merge OpenAI's qualification summary back onto the lead.
 * Handles n8n's OpenAI node Responses API shape (output[].content[].text)
 * plus legacy Chat Completion shapes for portability.
 */

const lead = $('Score Lead').item.json;
const ai = $input.item.json;

function extractContent(o) {
  if (!o) return "";

  // Responses API (current n8n OpenAI node default)
  // shape: { output: [ { content: [ { type: "output_text", text: "..." } ] } ] }
  if (Array.isArray(o.output) && o.output[0]?.content) {
    const block = o.output[0].content.find((c) => c.type === "output_text" || typeof c.text === "string");
    if (block?.text) return block.text;
  }

  // langchain wrapper
  if (typeof o.text === "string" && o.text.trim()) return o.text;

  // chat completion shape
  if (o.message?.content) return o.message.content;
  if (o.choices?.[0]?.message?.content) return o.choices[0].message.content;

  // generic fallbacks
  if (typeof o.content === "string") return o.content;
  if (typeof o.response === "string") return o.response;

  return "";
}

const summary = extractContent(ai).trim();

return {
  json: {
    ...lead,
    qualification_summary: summary,
    _ai: {
      model: "gpt-4o-mini",
      generated_at: new Date().toISOString()
    }
  }
};

/**
 * Build the HubSpot batch upsert payload from the canonical lead.
 *
 * Field mapping is explicit, easy to review, easy to extend.
 * Source channel is normalized to the canonical enum HubSpot expects
 * (raw inbound shape "website_form" → canonical "direct" attribution etc).
