const breakdown = scoring.breakdown || {};

// --- helpers ---
function splitName(full) {
  const parts = (full || "").trim().split(/\s+/);
  if (parts.length === 0) return { firstname: "", lastname: "" };
  if (parts.length === 1) return { firstname: parts[0], lastname: "" };
  return { firstname: parts[0], lastname: parts.slice(1).join(" ") };
}

function countryTier(country) {
  if (!country) return "out_of_market";
  if (["AE", "SA"].includes(country)) return "tier_1";
  if (country === "EG") return "tier_2";
  if (["KW", "BH", "QA", "OM", "JO"].includes(country)) return "tier_3";
  return "out_of_market";
}

function companySizeBand(size) {
  const n = Number(size);
  if (!n) return "unknown";
  if (n < 10)   return "micro";
  if (n < 20)   return "small";
  if (n <= 200) return "ideal";
  if (n <= 500) return "upper";
  if (n <= 1000) return "marginal_large";
  return "out_of_fit_large";
}

