// --- helpers ---
function countryLabel(country) {
  if (!country) return "Other";
  if (country === "AE") return "UAE";
  if (country === "SA") return "KSA";
  if (country === "EG") return "EGY";
  if (["KW","BH","QA","OM","JO"].includes(country)) return "GCC";
  return "Other";
}

function sourceLabel(canonical) {
  const map = {
    referral: "Referral", partner: "Partner", event: "Event", webinar: "Webinar",
    content_download: "Content", organic_search: "Organic", direct: "Direct",
    social_organic: "Social", paid_search: "Paid Search", paid_social: "Paid Social",
    cold_outbound: "Cold Outbound"
  };
  return map[canonical] || null;
}

function isStale(submittedAt) {
  if (!submittedAt) return false;
  const days = (Date.now() - new Date(submittedAt).getTime()) / 86400000;
  return days > 7;
}

function fmtSignals(arr) {
  return (arr || []).map((s) => `  - ${s}`).join("\n");
}

// --- pick board + labels ---
const tier = scoring.tier || "cold";
const target = TRELLO[tier];
if (!target) throw new Error(`Unknown tier: ${tier}`);

const labelsByName = target.labels;
const selectedLabels = [];

const cLabel = countryLabel(lead.country);
if (labelsByName[cLabel]) selectedLabels.push(labelsByName[cLabel]);

const langLabel = (lead.language || "en").toUpperCase();
if (labelsByName[langLabel]) selectedLabels.push(labelsByName[langLabel]);

const srcLabel = sourceLabel(lead._hubspot_canonical_source);
if (srcLabel && labelsByName[srcLabel]) selectedLabels.push(labelsByName[srcLabel]);

// flags
if ((lead.form_intent || "").toLowerCase().includes("demo") || /\bdemo\b/i.test(lead.raw_message || "")) {
  if (labelsByName["Demo Request"]) selectedLabels.push(labelsByName["Demo Request"]);
}
if (lead.existing_customer && labelsByName["Existing Customer"]) {
  selectedLabels.push(labelsByName["Existing Customer"]);
}
if (scoring.disqualified && labelsByName["Disqualified"]) {
  selectedLabels.push(labelsByName["Disqualified"]);
}
if ((scoring.confidence?.score ?? 1) < 0.6 && labelsByName["Low Confidence"]) {
  selectedLabels.push(labelsByName["Low Confidence"]);
}
if (isStale(lead.submitted_at) && labelsByName["Stale"]) {
  selectedLabels.push(labelsByName["Stale"]);
}

// --- card payload ---
const name = `[${scoring.total ?? "?"}] ${lead.company_name || "Unknown Co"} — ${lead.contact_name || "Unknown Contact"}`;

const desc = [
  `**Tier:** ${tier.toUpperCase()} — ${scoring.total ?? "?"}/100  |  Confidence: ${scoring.confidence?.score ?? "?"}`,
  ``,
  `**Qualification Summary**`,
  lead.qualification_summary || "_(no summary generated)_",
  ``,
  `**Lead Profile**`,
  `- Country: ${lead.country || "?"}  |  Industry: ${lead.industry || "?"}  |  Size: ${lead.company_size || "?"}`,
  `- Source: ${lead._hubspot_canonical_source || "unknown"} (raw: ${lead.source || "?"})`,
  `- Language: ${lead.language || "en"}`,
  `- Tech stack: ${(lead.tech_stack || []).join(", ") || "_none detected_"}`,
  ``,
  `**Score Breakdown**`,
  `- **Firmographic** ${breakdown.firmographic?.weighted ?? 0}/${breakdown.firmographic?.max ?? 0}`,
  fmtSignals(breakdown.firmographic?.signals),
  `- **Intent** ${breakdown.intent?.weighted ?? 0}/${breakdown.intent?.max ?? 0}`,
  fmtSignals(breakdown.intent?.signals),
  `- **Source Quality** ${breakdown.source_quality?.weighted ?? 0}/${breakdown.source_quality?.max ?? 0}`,
  fmtSignals(breakdown.source_quality?.signals),
  `- **Engagement** ${breakdown.engagement?.weighted ?? 0}/${breakdown.engagement?.max ?? 0}`,
  fmtSignals(breakdown.engagement?.signals),
  ``,
  `**Inbound Message**`,
  `> ${(lead.raw_message || "_(no message)_").replace(/\n/g, "\n> ")}`,
  ``,
  `---`,
  `🔗 [HubSpot Contact](${lead._hubspot?.contact_url || "#"})  |  📧 ${lead.email}  |  ☎️ ${lead.phone || "—"}`,
  `Request ID: \`${lead._request_id || "?"}\``
].join("\n");

const cardPayload = {
  idList: target.list_new,
  name,
  desc,
  idLabels: selectedLabels,        // array — for native Trello node
  idLabels_csv: selectedLabels.join(","),  // kept as fallback for HTTP Request
  pos: "top"
};

return {
  json: {
    ...lead,
    _trello_payload: cardPayload,
    _trello_target: { tier, board_id: target.board_id, list_id: target.list_new, labels_applied: selectedLabels.length }
  }
};

/**
 * Round-robin rep assignment within a geo + language bucket.
 *
 * Bucket strategy: country tier × language. A KSA Arabic lead goes
 * to a different bucket than a UAE English lead. Disqualified leads
 * skip assignment entirely (handled at switch downstream).
 *
 * Selection within bucket: deterministic hash of the lead's request_id.
 * This is *not* strict round-robin — strict RR requires a persistent
 * counter (Google Sheet, Redis, n8n static data). Hash-based gives
 * even distribution at scale and is reproducible (same lead always
 * goes to same rep, useful for re-runs and debugging).
 *
 * Production upgrade path documented in DESIGN_DECISIONS.md.
 */

const lead = $('Build Trello Card').item.json;
const trelloCard = $input.item.json;

// --- mock rep registry ---
// Each rep declares the buckets they cover (country_tier + languages).
const REPS = [
  { email: "sara@pemo.io",    name: "Sara Hassan",        slack: "U_SARA_MOCK",    countries: ["AE","SA"],          languages: ["en"]        },
  { email: "khalid@pemo.io",  name: "Khalid Al-Otaibi",   slack: "U_KHALID_MOCK",  countries: ["SA","AE","KW","QA"],languages: ["ar","en"]   },
  { email: "mohamed@pemo.io", name: "Mohamed Ali",        slack: "U_MOHAMED_MOCK", countries: ["EG","JO","LB"],     languages: ["ar","en"]   },
  { email: "layla@pemo.io",   name: "Layla Ahmed",        slack: "U_LAYLA_MOCK",   countries: ["AE"],               languages: ["en"]        },
  { email: "fallback@pemo.io",name: "Global Pool",        slack: "U_FALLBACK_MOCK",countries: ["*"],                languages: ["en","ar"]   }
];

function eligible(lead) {
  const country = lead.country || "";
  const lang = lead.language || "en";
  // Specific matches first — exclude wildcards
  const specific = REPS.filter((r) => {
    const countryOk = r.countries.includes(country) && !r.countries.includes("*");
    const langOk = r.languages.includes(lang);
    return countryOk && langOk;
  });
  return specific;
}

function fallback(lead) {
  const lang = lead.language || "en";
  return REPS.filter((r) => r.countries.includes("*") && r.languages.includes(lang));
}

// FNV-1a 32-bit hash, deterministic and dependency-free
function hash32(str) {
  let h = 2166136261;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h + ((h << 1) + (h << 4) + (h << 7) + (h << 8) + (h << 24))) >>> 0;
  }
  return h;
}

function pickRep(lead) {
  const specificPool = eligible(lead);
  const pool = specificPool.length > 0 ? specificPool : fallback(lead);
  if (pool.length === 0) {
    return { rep: null, reason: `no rep covers country=${lead.country} language=${lead.language}` };
  }
  const idx = hash32(lead._request_id || lead.email || "") % pool.length;
  const reasonNote = specificPool.length > 0
    ? `bucket=${lead.country}/${lead.language}, ${pool.length} specific rep(s) eligible`
    : `bucket=${lead.country}/${lead.language}, no specific rep — falling back to global pool`;
  return { rep: pool[idx], reason: reasonNote };
}

const { rep, reason } = pickRep(lead);

return {
  json: {
    ...lead,
    _trello_card: {
      id: trelloCard.id,
      url: trelloCard.url,
      shortUrl: trelloCard.shortUrl,
      idList: trelloCard.idList,
      idBoard: trelloCard.idBoard
    },
    _assignment: rep
      ? {
          rep_email: rep.email,
          rep_name: rep.name,
          rep_slack: rep.slack,
          bucket_reason: reason,
          assigned_at: new Date().toISOString()
        }
      : {
          rep_email: null,
          rep_name: null,
          rep_slack: null,
          bucket_reason: reason,
          assigned_at: new Date().toISOString(),
          unassigned: true
        }
  }
};
